import{_ as i,o,c as n,ag as a}from"./chunks/framework.DAvaMl8U.js";const p=JSON.parse('{"title":"Core: Chunking","description":"","frontmatter":{},"headers":[],"relativePath":"core-chunking.md","filePath":"core-chunking.md"}'),r={name:"core-chunking.md"};function t(l,e,c,s,d,u){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="core-chunking" tabindex="-1">Core: Chunking <a class="header-anchor" href="#core-chunking" aria-label="Permalink to &quot;Core: Chunking&quot;">​</a></h1><p>Chunking transforms normalized text into search units.</p><p>Source module:</p><ul><li><code>backend/src/chunking/chunk-processor.ts</code></li></ul><hr><h2 id="behavior" tabindex="-1">Behavior <a class="header-anchor" href="#behavior" aria-label="Permalink to &quot;Behavior&quot;">​</a></h2><p><code>processChunks(...)</code> does four things:</p><ol><li>Delete prior chunks for the document</li><li>Split content using <code>chunkText(content, 800, 100)</code></li><li>Compute token count per chunk via <code>approximateTokenCount(...)</code></li><li>Insert each chunk with stable <code>chunk_index</code></li></ol><p>Returns <code>ProcessedChunk[]</code> with:</p><ul><li><code>index</code></li><li><code>text</code></li><li><code>tokenCount</code></li></ul><hr><h2 id="why-full-replace-is-used" tabindex="-1">Why full replace is used <a class="header-anchor" href="#why-full-replace-is-used" aria-label="Permalink to &quot;Why full replace is used&quot;">​</a></h2><p>Chunk rows are deleted and re-inserted rather than diffed.</p><p>Reason:</p><ul><li>Content edits shift boundaries, making chunk-level diffs brittle.</li><li>Full replace keeps ordering and snippet behavior deterministic.</li></ul><hr><h2 id="key-sql-usage" tabindex="-1">Key SQL usage <a class="header-anchor" href="#key-sql-usage" aria-label="Permalink to &quot;Key SQL usage&quot;">​</a></h2><ul><li><code>SQL_DELETE_DOCUMENT_CHUNKS</code></li><li><code>SQL_INSERT_DOCUMENT_CHUNK</code></li></ul><p>This stage is pure chunk persistence; search ranking vectors are updated in indexing.</p>',19)])])}const k=i(r,[["render",t]]);export{p as __pageData,k as default};
